async function _deleteStaleToken(companyId, uid) {
  await Promise.allSettled([
    admin.firestore().collection("kunden").doc(companyId).collection("users").doc(uid)
      .update({ fcmToken: admin.firestore.FieldValue.delete() }),
    admin.firestore().collection("fcmTokens").doc(uid).delete(),
  ]);
  console.info(`FCM-Token-Cleanup: uid=${uid} aus beiden Collections geloescht`);
}
function _isStaleTokenError(code) {
  return (
    code.includes("registration-token-not-registered") ||
    code.includes("invalid-registration-token")
  );
}

/** Firestore-Trigger: Bei Einsatz (alarmierung-nfs) erstellt/aktualisiert - Alarm-Push an neu alarmierte Mitarbeiter */
exports.onAlarmierungNfsWrite = functions.region("europe-west1").firestore
  .document("kunden/{companyId}/alarmierung-nfs/{einsatzId}")
  .onWrite(async (change, context) => {
    const { companyId, einsatzId } = context.params;
    if (!PUSH_ENABLED) {
      console.log("onAlarmierungNfsWrite: Push deaktiviert, companyId=" + companyId);
      return;
    }
    const newEinsatz = change.after.exists ? change.after.data() : null;
    const oldEinsatz = change.before.exists ? change.before.data() : null;
    if (!newEinsatz) {
      console.log("onAlarmierungNfsWrite: Einsatz geloescht, einsatzId=" + einsatzId);
      return;
    }
    const newIds = Array.isArray(newEinsatz.alarmierteMitarbeiterIds)
      ? newEinsatz.alarmierteMitarbeiterIds.map(String)
      : [];
    const oldIds = Array.isArray(oldEinsatz?.alarmierteMitarbeiterIds)
      ? oldEinsatz.alarmierteMitarbeiterIds.map(String)
      : [];
    let recipientsToNotify = [];
    if (!oldEinsatz) {
      recipientsToNotify = newIds;
      console.log("onAlarmierungNfsWrite: Neuer Einsatz " + einsatzId + ", " + recipientsToNotify.length + " alarmiert");
    } else {
      recipientsToNotify = newIds.filter((id) => !oldIds.includes(id));
      if (recipientsToNotify.length === 0) {
        console.log("onAlarmierungNfsWrite: Keine neuen Alarmierungen, einsatzId=" + einsatzId);
        return;
      }
      console.log("onAlarmierungNfsWrite: Einsatz " + einsatzId + " aktualisiert, " + recipientsToNotify.length + " neu alarmiert");
    }
    if (recipientsToNotify.length === 0) return;
    const title = (newEinsatz.stichwort || "Einsatz").toString().trim();
    const body = (newEinsatz.einsatzort || "Neue Alarmierung").toString().trim();
    const recipientPromises = recipientsToNotify.map(async (mitarbeiterId) => {
      try {
        const mitarbeiterSnap = await admin.firestore()
          .collection("kunden").doc(companyId).collection("mitarbeiter").doc(mitarbeiterId).get();
        const uid = mitarbeiterSnap.exists ? (mitarbeiterSnap.data()?.uid || "").trim() : "";
        if (!uid) {
          console.warn("onAlarmierungNfsWrite: Kein UID fuer mitarbeiterId=" + mitarbeiterId);
          return;
        }
        const token = await getFcmToken(companyId, uid);
        if (token) {
          await sendAlarmPush(token, title, body, companyId, einsatzId, uid);
          console.log("onAlarmierungNfsWrite: Alarm-Push an uid=" + uid + " fuer einsatzId=" + einsatzId);
        } else {
          console.log("onAlarmierungNfsWrite: Kein FCM-Token fuer uid=" + uid);
        }
      } catch (error) {
        const code = String(error.code || error.errorInfo?.code || "");
        if (_isStaleTokenError(code)) {
          const mitarbeiterSnap = await admin.firestore()
            .collection("kunden").doc(companyId).collection("mitarbeiter").doc(mitarbeiterId).get();
          const uidToDelete = mitarbeiterSnap.exists ? (mitarbeiterSnap.data()?.uid || "").trim() : "";
          if (uidToDelete) {
            await _deleteStaleToken(companyId, uidToDelete);
            console.warn("onAlarmierungNfsWrite: Veralteter Token fuer uid=" + uidToDelete + " geloescht");
          }
        } else {
          console.error("onAlarmierungNfsWrite: Fehler fuer mitarbeiterId=" + mitarbeiterId + ":", error);
        }
      }
    });
    await Promise.allSettled(recipientPromises);
    console.log("onAlarmierungNfsWrite: Verarbeitung " + einsatzId + " abgeschlossen");
  });

